// Kill switch — set to true to disable all Meta writes
const KILL_SWITCH = false;
if (KILL_SWITCH) throw new Error('KILL_SWITCH_ACTIVE: Meta writes are globally disabled.');

let payload;
try {
  payload = typeof $json.body?.payload === 'string' ? JSON.parse($json.body.payload) : ($json.body?.payload || $json);
} catch(e) { throw new Error('Failed to parse Slack payload: ' + e.message); }

const actionValue = payload?.actions?.[0]?.value || '';
const [plan_id, decision] = actionValue.split('|');
const user = payload?.user?.name || payload?.user?.username || 'unknown';
if (!plan_id || !decision) throw new Error('Invalid payload: missing plan_id or decision.');
return [{ json: { plan_id, decision, user } }];

const plan = $('Load Plan + Performance').item.json;
const actions = plan.actions || [];
const recentPerf = plan.recent_performance || [];
const maxBudgetChangePct = 20;
const minConversions = 10;

const perfMap = {};
for (const p of recentPerf) { perfMap[p.entity_id] = { conversions_7d: p.conversions_7d||0, spend_7d: p.spend_7d||0 }; }

const safeActions = [], blockedActions = [];
for (const action of actions) {
  const perf = perfMap[action.entity_id] || { conversions_7d: 0, spend_7d: 0 };
  if (action.action_type === 'scale_budget') {
    if (perf.conversions_7d < minConversions) { blockedActions.push({ ...action, block_reason: `Insufficient conversions: ${perf.conversions_7d} < ${minConversions}` }); continue; }
    const changePct = Math.abs(action.delta?.budget_change_pct || 0);
    if (changePct > maxBudgetChangePct) { blockedActions.push({ ...action, block_reason: `Budget change ${changePct}% exceeds cap ${maxBudgetChangePct}%` }); continue; }
  }
  safeActions.push({ ...action, plan_id: plan.plan_id, perf });
}
if (safeActions.length === 0) throw new Error(`All ${actions.length} actions blocked. ${JSON.stringify(blockedActions)}`);
return safeActions.map(a => ({ json: a }));
